import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { FileText, ClipboardList, Users, Plus, ChevronDown, PackageOpen, CheckCircle2 } from 'lucide-react';
import { getDashboard } from '../../services/api';
import Loading from '../common/Loading';
import { formatCurrency, formatDate, badgeClass } from '../../utils/formatters';

const sections = [
  { key: 'presupuestos', label: 'PRESUPUESTOS', icon: FileText, dataKey: 'presupuestos_recientes' },
  { key: 'ordenes', label: 'ÓRDENES', icon: ClipboardList, dataKey: 'ordenes_recientes' },
  { key: 'stock', label: 'STOCK DE PILETAS', icon: PackageOpen, dataKey: 'piletas' },
];

export default function Dashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [section, setSection] = useState('presupuestos');
  const [open, setOpen] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    getDashboard()
      .then((res) => setData(res.data))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <Loading />;

  const stats = [
    { label: 'Presupuestos Pendientes', value: data?.presupuestos_pendientes || 0, color: '#f59e0b', bg: '#fef3c7', icon: FileText },
    { label: 'Órdenes Presupuestadas', value: data?.ordenes_presupuestadas || 0, color: '#3b82f6', bg: '#dbeafe', icon: ClipboardList },
    { label: 'Órdenes en Producción', value: data?.ordenes_en_produccion || 0, color: '#8b5cf6', bg: '#ede9fe', icon: ClipboardList },
    { label: 'Órdenes Finalizadas', value: data?.ordenes_finalizadas || 0, color: '#22c55e', bg: '#dcfce7', icon: ClipboardList },
    { label: 'Piletas en Stock', value: data?.piletas_en_stock || 0, color: '#06b6d4', bg: '#cffafe', icon: PackageOpen },
    { label: 'Próximas Entregas', value: data?.trabajos_proxima_entrega || 0, color: '#f97316', bg: '#fff7ed', icon: FileText },
  ];

  const current = sections.find((s) => s.key === section);
  const items = data?.[current.dataKey] || [];

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <h1 style={{ fontSize: 24, fontWeight: 700 }}>Dashboard</h1>
        <div style={{ display: 'flex', gap: 10 }}>
          <button className="btn btn-primary" onClick={() => navigate('/presupuestos/nuevo')}>
            <Plus size={16} /> Nuevo Presupuesto
          </button>
          <button className="btn btn-success" onClick={() => navigate('/ordenes/nuevo')}>
            <Plus size={16} /> Nueva Orden
          </button>
          <button className="btn btn-outline" onClick={() => navigate('/clientes/nuevo')}>
            <Plus size={16} /> Nuevo Cliente
          </button>
        </div>
      </div>

      <div className="grid-4">
        {stats.map((s, i) => (
          <div key={i} className="stat-card">
            <div className="icon" style={{ background: s.bg }}>
              <s.icon size={22} color={s.color} />
            </div>
            <div className="value" style={{ color: s.color }}>{s.value}</div>
            <div className="label">{s.label}</div>
          </div>
        ))}
      </div>

      <div style={{ marginTop: 32 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
          <h2 className="section-title" style={{ margin: 0 }}>
            {current.icon && <current.icon size={20} style={{ marginRight: 8, verticalAlign: 'middle' }} />}
            {current.label}
          </h2>
          <div style={{ position: 'relative' }}>
            <button
              className="btn btn-outline"
              onClick={() => setOpen(!open)}
              style={{ display: 'flex', alignItems: 'center', gap: 8, minWidth: 200, justifyContent: 'space-between' }}
            >
              {current.label} <ChevronDown size={16} />
            </button>
            {open && (
              <div
                style={{
                  position: 'absolute', top: '100%', right: 0, marginTop: 4,
                  background: '#fff', border: '1px solid #e5e7eb', borderRadius: 12,
                  boxShadow: '0 10px 25px rgba(0,0,0,0.1)', zIndex: 50, minWidth: 220, overflow: 'hidden',
                }}
              >
                {sections.map((s) => (
                  <div
                    key={s.key}
                    onClick={() => { setSection(s.key); setOpen(false); }}
                    style={{
                      padding: '12px 16px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 10,
                      fontWeight: section === s.key ? 600 : 400,
                      background: section === s.key ? '#f3f4f6' : 'transparent',
                      borderBottom: '1px solid #f3f4f6',
                    }}
                  >
                    <s.icon size={18} />
                    {s.label}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {section === 'stock' ? (
          <div className="table-container">
            <table className="table">
              <thead>
                <tr>
                  <th>Marca</th>
                  <th>Modelo</th>
                  <th>Cantidad</th>
                </tr>
              </thead>
              <tbody>
                {items.length === 0 ? (
                  <tr><td colSpan={3} style={{ textAlign: 'center', padding: 24, color: '#9ca3af' }}>Sin stock registrado</td></tr>
                ) : items.map((p) => (
                  <tr key={p.id} style={{ cursor: 'pointer' }} onClick={() => navigate('/stock-piletas')}>
                    <td>{p.marca}</td>
                    <td>{p.modelo}</td>
                    <td>{p.cantidad}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="table-container">
            <table className="table">
              <thead>
                <tr>
                  <th>N°</th>
                  <th>Cliente</th>
                  <th>Total</th>
                  <th>Estado</th>
                  <th>Fecha</th>
                </tr>
              </thead>
              <tbody>
                {items.length === 0 ? (
                  <tr><td colSpan={5} style={{ textAlign: 'center', padding: 24, color: '#9ca3af' }}>Sin registros</td></tr>
                ) : items.map((item) => (
                  <tr key={item.id} style={{ cursor: 'pointer' }}
                    onClick={() => navigate(section === 'presupuestos' ? `/presupuestos/${item.id}` : `/ordenes/${item.id}`)}
                  >
                    <td><strong>{item.numero}</strong></td>
                    <td>{item.cliente_nombre || '-'}</td>
                    <td>{formatCurrency(item.total)}</td>
                    <td><span className={badgeClass(item.estado)}>{item.estado}</span></td>
                    <td>{item.created_at ? formatDate(item.created_at) : '-'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {data?.ordenes_entregadas?.length > 0 && (
        <div style={{ marginTop: 40 }}>
          <h2 className="section-title" style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <CheckCircle2 size={20} /> ÓRDENES ENTREGADAS
          </h2>
          <p style={{ color: '#6b7280', fontSize: 14, marginBottom: 12 }}>
            Órdenes entregadas con más de 2 meses de antigüedad
          </p>
          <div className="table-container">
            <table className="table">
              <thead>
                <tr>
                  <th>N°</th>
                  <th>Cliente</th>
                  <th>Total</th>
                  <th>Estado</th>
                  <th>Entregada</th>
                </tr>
              </thead>
              <tbody>
                {data.ordenes_entregadas.map((o) => (
                  <tr key={o.id} style={{ cursor: 'pointer', opacity: 0.7 }}
                    onClick={() => navigate(`/ordenes/${o.id}`)}
                  >
                    <td><strong>{o.numero}</strong></td>
                    <td>{o.cliente_nombre || '-'}</td>
                    <td>{formatCurrency(o.total)}</td>
                    <td><span className={badgeClass(o.estado)}>{o.estado}</span></td>
                    <td>{o.updated_at ? formatDate(o.updated_at) : '-'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}
